import {
  Component,
  Prop,
  State,
  Event,
  EventEmitter,
  Element,
  h,
  Listen,
} from '@stencil/core';
import type {
  DropdownMenuItem,
  DropdownMenuHeader,
} from '../bh-dropdown-menu/bh-dropdown-menu';

export type DropdownSize = 'sm' | 'md';
export type DropdownState = 'default' | 'focus' | 'disabled';
export type DropdownVariant =
  | 'outlined'
  | 'ghost'
  | 'icon-only-outlined'
  | 'icon-only-ghost'
  | 'avatar';

@Component({
  tag: 'bh-dropdown',
  styleUrl: 'bh-dropdown.css',
  shadow: true,
})
export class BhDropdown {
  @Element() el!: HTMLElement;

  /**
   * Size of the dropdown trigger
   */
  @Prop() size: DropdownSize = 'md';

  /**
   * State of the dropdown
   */
  @Prop() state: DropdownState = 'default';

  /**
   * Visual variant of the dropdown trigger
   */
  @Prop() variant: DropdownVariant = 'outlined';

  /**
   * Label for the dropdown button
   */
  @Prop() label: string = 'Options';

  /**
   * Icon name for icon-only variants
   */
  @Prop() iconName: string = 'more_vert';

  /**
   * Whether the dropdown is disabled
   */
  @Prop() disabled: boolean = false;

  /**
   * Menu items (JSON string or array)
   */
  @Prop() menuItems: DropdownMenuItem[] | string = [];

  /**
   * Header configuration (JSON string or object)
   */
  @Prop() header?: DropdownMenuHeader | string;

  /**
   * Avatar image source for avatar variant
   */
  @Prop() avatarSrc: string = '';

  /**
   * Avatar alt text
   */
  @Prop() avatarAlt: string = 'Avatar';

  /**
   * Avatar size for avatar variant
   */
  @Prop() avatarSize: 'sm' | 'md' | 'lg' = 'md';

  /**
   * Avatar name for header
   */
  @Prop() avatarName?: string;

  /**
   * Avatar email for header
   */
  @Prop() avatarEmail?: string;

  /**
   * Whether to show icons in menu items
   */
  @Prop() showIcons: boolean = true;

  @State() isOpen: boolean = false;

  /**
   * Event emitted when a menu item is clicked
   */
  @Event() bhItemClick!: EventEmitter<DropdownMenuItem>;

  @Listen('click', { target: 'document' })
  handleClickOutside(event: MouseEvent) {
    if (this.isOpen && !this.el.contains(event.target as Node)) {
      this.isOpen = false;
    }
  }

  private get parsedMenuItems(): DropdownMenuItem[] {
    if (typeof this.menuItems === 'string') {
      try {
        return JSON.parse(this.menuItems);
      } catch {
        return [];
      }
    }
    return this.menuItems || [];
  }

  private get parsedHeader(): DropdownMenuHeader | undefined {
    if (this.variant === 'avatar') {
      return {
        avatarGroup: true,
        avatarSrc: this.avatarSrc,
        name: this.avatarName,
        email: this.avatarEmail,
      };
    }
    if (!this.header) return undefined;
    if (typeof this.header === 'string') {
      try {
        return JSON.parse(this.header);
      } catch {
        return undefined;
      }
    }
    return this.header;
  }

  private toggleDropdown = () => {
    if (this.disabled) return;
    this.isOpen = !this.isOpen;
  };

  private handleMenuItemClick = (event: CustomEvent<DropdownMenuItem>) => {
    const item = event.detail;
    if (!item.disabled) {
      this.bhItemClick.emit(item);
      this.isOpen = false;
    }
  };

  private get isIconOnly(): boolean {
    return (
      this.variant === 'icon-only-outlined' ||
      this.variant === 'icon-only-ghost'
    );
  }

  private get showAvatar(): boolean {
    return this.variant === 'avatar';
  }

  private get buttonHierarchy(): 'secondary' | 'tertiary' {
    return this.variant === 'ghost' || this.variant === 'icon-only-ghost'
      ? 'tertiary'
      : 'secondary';
  }

  render() {
    const containerClasses = {
      'dropdown-container': true,
      'dropdown-open': this.isOpen,
      'dropdown-avatar-variant': this.variant === 'avatar',
    };

    const avatarClasses = {
      'dropdown-avatar': true,
      'dropdown-avatar-focus': this.isOpen,
      'dropdown-avatar-disabled': this.disabled,
    };

    return (
      <div class={containerClasses}>
        {/* Button variants */}
        {!this.showAvatar && (
          <bh-button
            hierarchy={this.buttonHierarchy}
            icon={this.isIconOnly ? 'only' : 'trailing'}
            size={this.size}
            label={this.isIconOnly ? '' : this.label}
            iconName={this.isIconOnly ? this.iconName : 'expand_more'}
            disabled={this.disabled}
            onClick={this.toggleDropdown}
          />
        )}

        {/* Avatar variant */}
        {this.showAvatar && (
          <div
            class={avatarClasses}
            onClick={(e) => {
              if (!this.disabled) {
                e.stopPropagation();
                this.toggleDropdown();
              }
            }}
            role="button"
            tabindex={this.disabled ? -1 : 0}
            onKeyDown={(e: KeyboardEvent) => {
              if (!this.disabled && (e.key === 'Enter' || e.key === ' ')) {
                e.preventDefault();
                this.toggleDropdown();
              }
            }}
          >
            <bh-avatar
              type="image"
              size={this.avatarSize}
              imageSrc={this.avatarSrc}
              alt={this.avatarAlt}
            />
          </div>
        )}

        {/* Menu */}
        <bh-dropdown-menu
          visible={this.isOpen}
          showIcons={this.showIcons}
          menuItems={JSON.stringify(this.parsedMenuItems)}
          header={
            this.parsedHeader ? JSON.stringify(this.parsedHeader) : undefined
          }
          onBhItemClick={this.handleMenuItemClick}
        />
      </div>
    );
  }
}
